import pandas as pd
import openpyxl
from openpyxl.utils.dataframe import dataframe_to_rows
from openpyxl.styles import NamedStyle
import numpy as np

def combine_cdnr_to_b2b():
    # Load the workbook
    wb = openpyxl.load_workbook('/Users/thomascahill/Documents/servalsheets 2/benchmark/spreadsheetbench/data/spreadsheetbench_verified_400/spreadsheet/130-9/1_130-9_init.xlsx')

    # Get the sheets
    dest_sheet = wb['b2b, sez, de']
    source_sheet = wb['cdnr']

    # Read headers from row 3 (index 2) of both sheets
    dest_headers = []
    source_headers = []

    # Get destination headers (row 3)
    for cell in dest_sheet[3]:
        dest_headers.append(cell.value)

    # Get source headers (row 3)
    for cell in source_sheet[3]:
        source_headers.append(cell.value)

    # Create mapping between source and destination columns based on header text
    column_mapping = {}
    for src_idx, src_header in enumerate(source_headers):
        if src_header in dest_headers:
            dest_idx = dest_headers.index(src_header)
            column_mapping[src_idx] = dest_idx

    # Find the first empty row in destination (should be row 7 as mentioned)
    first_empty_row = 7

    # Get all data rows from source sheet (starting from row 4)
    source_data_rows = []
    for row_num in range(4, source_sheet.max_row + 1):
        row_data = []
        for cell in source_sheet[row_num]:
            row_data.append(cell.value)
        # Only add non-empty rows
        if any(cell is not None and cell != '' for cell in row_data):
            source_data_rows.append(row_data)

    # Copy and transform data
    current_dest_row = first_empty_row

    for source_row in source_data_rows:
        # Create a new row for destination with same number of columns as destination
        dest_row_data = [None] * len(dest_headers)

        # Map data from source to destination based on header alignment
        for src_col_idx, dest_col_idx in column_mapping.items():
            if src_col_idx < len(source_row):
                value = source_row[src_col_idx]

                # Special handling for columns L and M (indices 11 and 12) - make amounts negative
                if dest_col_idx in [11, 12] and value is not None:
                    try:
                        if isinstance(value, (int, float)) and value != 0:
                            value = -abs(value)
                        elif isinstance(value, str):
                            try:
                                num_val = float(value)
                                if num_val != 0:
                                    value = -abs(num_val)
                            except ValueError:
                                pass
                    except:
                        pass

                dest_row_data[dest_col_idx] = value

        # Set column H (index 7) to blank and column I (index 8) to "Credit Note"
        if len(dest_row_data) > 7:
            dest_row_data[7] = None  # Column H - blank
        if len(dest_row_data) > 8:
            dest_row_data[8] = "Credit Note"  # Column I

        # Write the row to destination sheet
        for col_idx, value in enumerate(dest_row_data):
            if col_idx < len(dest_headers):
                cell = dest_sheet.cell(row=current_dest_row, column=col_idx + 1)
                cell.value = value

                # Preserve number formatting for columns L and M if they had formatting
                if col_idx in [11, 12]:  # Columns L and M
                    # Try to copy number format from existing cells in these columns
                    if current_dest_row > 4:  # If there are existing data rows
                        try:
                            reference_cell = dest_sheet.cell(row=4, column=col_idx + 1)
                            if reference_cell.number_format:
                                cell.number_format = reference_cell.number_format
                        except:
                            pass

        current_dest_row += 1

    # Save the workbook
    wb.save('/Users/thomascahill/Documents/servalsheets 2/benchmark/spreadsheetbench/data/spreadsheetbench_verified_400/outputs/single_claude-sonnet-4-20250514/1_130-9_output.xlsx')

# Execute the function
combine_cdnr_to_b2b()

import pandas as pd
import openpyxl
from openpyxl import load_workbook
import re

# Load the workbook
wb = load_workbook('/Users/thomascahill/Documents/servalsheets 2/benchmark/spreadsheetbench/data/spreadsheetbench_verified_400/spreadsheet/41-47/1_41-47_init.xlsx')

# Read data from source sheets
sheets_data = {}
for sheet_name in ['CMSN', 'CSTR', 'EXPRO']:
    if sheet_name in wb.sheetnames:
        ws = wb[sheet_name]
        data = []
        headers = [cell.value for cell in ws[1]]
        for row in ws.iter_rows(min_row=2, values_only=True):
            if any(cell is not None for cell in row):
                data.append(row)
        sheets_data[sheet_name] = pd.DataFrame(data, columns=headers)

# Combine all data
all_data = []
for sheet_name, df in sheets_data.items():
    if not df.empty:
        all_data.append(df)

if all_data:
    combined_df = pd.concat(all_data, ignore_index=True)
else:
    combined_df = pd.DataFrame()

# Function to extract item number from REF for sorting
def extract_item_number(ref_str):
    if pd.isna(ref_str):
        return float('inf')
    match = re.search(r'(\d+)', str(ref_str))
    return int(match.group(1)) if match else float('inf')

# Categorize data by account type
categories = {
    'PUR PURCHASE': [],
    'PUR PAID': [],
    'CASH SS': [],
    'EXPRR': []
}

for _, row in combined_df.iterrows():
    account = str(row['ACCOUNT REF']) if pd.notna(row['ACCOUNT REF']) else ''
    amount = row['CREDIT'] if pd.notna(row['CREDIT']) else row['DEBIT']

    if 'PUR PURCHASE' in account:
        categories['PUR PURCHASE'].append({
            'REF': account,
            'AMOUNT': amount,
            'sort_key': extract_item_number(account)
        })
    elif 'PUR PAID' in account:
        categories['PUR PAID'].append({
            'REF': account,
            'AMOUNT': amount,
            'sort_key': extract_item_number(account)
        })
    elif 'CASH SS' in account:
        categories['CASH SS'].append({
            'REF': account,
            'AMOUNT': amount,
            'sort_key': extract_item_number(account)
        })
    elif 'EXPRR' in account:
        categories['EXPRR'].append({
            'REF': account,
            'AMOUNT': amount,
            'sort_key': extract_item_number(account)
        })

# Sort each category by item number
for category in categories:
    categories[category].sort(key=lambda x: x['sort_key'])

# Clear existing data in OUT CAS sheet
out_cas_ws = wb['OUT CAS']

# Clear the specified ranges
ranges_to_clear = [
    'A2:C1529',
    'E2:G586', 
    'I2:K13',
    'L2:O8'
]

for range_str in ranges_to_clear:
    for row in out_cas_ws[range_str]:
        for cell in row:
            cell.value = None

# Write data to appropriate columns
# PUR PURCHASE -> Columns A, B, C
start_row = 2
for i, item in enumerate(categories['PUR PURCHASE']):
    if start_row + i <= 1529:  # Within the specified range
        out_cas_ws.cell(row=start_row + i, column=1, value=i + 1)  # ITEM
        out_cas_ws.cell(row=start_row + i, column=2, value=item['REF'])  # PUR PURCHASE
        out_cas_ws.cell(row=start_row + i, column=3, value=item['AMOUNT'])  # AMOUNT

# PUR PAID -> Columns E, F, G
start_row = 2
for i, item in enumerate(categories['PUR PAID']):
    if start_row + i <= 586:  # Within the specified range
        out_cas_ws.cell(row=start_row + i, column=5, value=i + 1)  # ITEM
        out_cas_ws.cell(row=start_row + i, column=6, value=item['REF'])  # PUR PAID
        out_cas_ws.cell(row=start_row + i, column=7, value=item['AMOUNT'])  # AMOUNT

