ws = wb.active

# Extract the values from the spreadsheet (using 1-indexed Excel coordinates)
target = ws['B3'].value      # Target: 840
stretch = ws['C3'].value     # Stretch: 1120.672
overstretch = ws['D3'].value # Over Stretch: 1399.93
total = ws['F3'].value       # Total: 1094

# Calculate points using the nested IF logic
def calculate_points(total, target, stretch, overstretch):
    base_ratio = total / target

    if total <= target:
        return base_ratio
    elif total > target and total < stretch:
        return min(base_ratio, 1.09)
    elif total == stretch:
        return min(base_ratio, 1.1)
    elif total > stretch and total < overstretch:
        return min(base_ratio, 1.19)
    else:  # total >= overstretch
        return min(base_ratio, 1.2)

# Calculate the points
points = calculate_points(total, target, stretch, overstretch)

# Update the Points cell G3
ws['G3'] = points

